// src/pages/MarketingHome.js
import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Award, Clock, Shield, Check } from 'lucide-react';
import Navbar from '../components/layout/Navbar'; // Update this path if needed
import Footer from '../components/layout/Footer'; // Update this path if needed

const MarketingHome = () => {
  const [email, setEmail] = useState('');
  const navigate = useNavigate();
  
  const handleSignup = (e) => {
    e.preventDefault();
    localStorage.setItem('signupEmail', email);
    navigate('/register');
  };

  return (
    <div className="bg-gray-50 min-h-screen">
      {/* Fixed navbar */}
      <Navbar />
      
      {/* Padding to create space for fixed navbar */}
      <div className="pt-20"></div>
      
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-blue-600 to-blue-800 text-white rounded-lg overflow-hidden shadow-xl mb-12 mx-4 md:mx-8 lg:mx-auto lg:max-w-7xl">
        {/* Rest of your hero section */}
      </section>

      {/* Rest of your sections */}
      
      <Footer />
    </div>
  );
};

export default MarketingHome;
